import{_ as o,c as e,o as r,ag as a}from"./chunks/framework.Ds6Eueu6.js";const d="/assets/01-gdp-ic-comparison.3dgKUNWu.png",n="/assets/01-gdp-rank-comparison.mS5D4wL2.png",s="/assets/02-momentum-ic-grid.BV6IZaOi.png",l="/assets/02-grouped-ic-comparison.CItUaGqZ.png",p="/assets/03-strategy-comparison.DdG5r2Ye.png",m=JSON.parse('{"title":"第九章：持续寻找盈利机会：因子研究入门","description":"","frontmatter":{},"headers":[],"relativePath":"book/q9-daily-work.md","filePath":"book/q9-daily-work.md","lastUpdated":null}'),i={name:"book/q9-daily-work.md"};function c(h,t,g,u,b,q){return r(),e("div",null,t[0]||(t[0]=[a('<h1 id="第九章-持续寻找盈利机会-因子研究入门" tabindex="-1">第九章：持续寻找盈利机会：因子研究入门 <a class="header-anchor" href="#第九章-持续寻找盈利机会-因子研究入门" aria-label="Permalink to &quot;第九章：持续寻找盈利机会：因子研究入门&quot;">​</a></h1><p>前面八章，我们从零搭建了一个完整的量化策略——选标的、定仓位、择时买卖、验证有效性、避免过拟合、接入执行、持续迭代。策略跑起来了。</p><p><strong>然后呢？</strong></p><p>做完一个策略就结束了吗？量化交易员的日常到底在忙什么？</p><p>答案是：<strong>因子研究</strong>。</p><p>回头看前面八章的每一个关键决策——用 GDP 选国家、用动量排名买卖——背后都有一个共同的逻辑：找到一个数据指标，用它来做决策。这个数据指标，就是<strong>因子（Factor）</strong>。</p><p>量化交易员的日常工作，就是不断寻找新的因子、评估它们的预测能力、组合成更好的信号、改进策略。这一章，我们就来体验这个过程。</p><h3 id="路线图" tabindex="-1">路线图 <a class="header-anchor" href="#路线图" aria-label="Permalink to &quot;路线图&quot;">​</a></h3><p><strong>完整跑通一个策略（第一章）→ 选什么标的（第二章）→ 每个买多少（第三章）→ 什么时候买卖（第四章）→ 怎么验证有效（第五章）→ 如何避免自欺欺人（第六章）→ 怎么真正执行（第七章）→ 如何持续改进（第八章）→ 持续找下一个 alpha（第九章本章）</strong></p><p>本章从“回顾已有决策”出发，正式引入因子概念，用三个步骤体验量化研究员的日常工作，三步的问题与方法对照如表 9-1 所示。</p><p><strong>表 9-1 第九章三步实验问题与方法对照</strong></p><table tabindex="0"><thead><tr><th>步骤</th><th>问题</th><th>方法</th></tr></thead><tbody><tr><td>Step 1</td><td>前面的决策靠的是什么？</td><td>回顾 → 引入因子概念 → IC 评估方法 → GDP 因子实验</td></tr><tr><td>Step 2</td><td>动量因子到底靠不靠谱？</td><td>25 只 ETF × 多个前向窗口 → IC 分析 → 分组诊断</td></tr><tr><td>Step 3</td><td>因子评估能改进策略吗？</td><td>补充因子 → 发现问题 → 波动率过滤 → 回测验证</td></tr></tbody></table><p>（操作流程见前言“怎么使用这本书”。）</p><hr><h2 id="_9-1-从直觉到因子" tabindex="-1">9.1 从直觉到因子 <a class="header-anchor" href="#_9-1-从直觉到因子" aria-label="Permalink to &quot;9.1 从直觉到因子&quot;">​</a></h2><p>回顾一下前面课程中的两个关键决策，对照如表 9-2 所示。</p><p><strong>表 9-2 前面课程中的两个关键决策回顾</strong></p><table tabindex="0"><thead><tr><th>章节</th><th>决策</th><th>用了什么数据</th><th>因子名称</th><th>因子类别</th></tr></thead><tbody><tr><td>第二章选什么</td><td>选哪个国家的市场</td><td>GDP 总量/增速</td><td>GDP 因子</td><td>宏观因子</td></tr><tr><td>第三章买多少</td><td>涨的多买、跌的不买</td><td>风险调整动量</td><td>动量因子</td><td>动量因子</td></tr></tbody></table><p>你可能没意识到，第二章和第三章里你已经在用因子了。**因子（Factor）**就是你做投资决策时参考的那个数据——GDP 高的国家更值得投、涨得好的多买一点。就像你挑餐厅会看评分、看距离、看价格，这些“参考指标”就是因子。</p><p>量化研究的日常工作，就是不断寻找和评估这些因子。</p><h3 id="怎么评估一个因子好不好" tabindex="-1">怎么评估一个因子好不好？ <a class="header-anchor" href="#怎么评估一个因子好不好" aria-label="Permalink to &quot;怎么评估一个因子好不好？&quot;">​</a></h3><p>一个因子好不好，最直接的检验方式是：它的打分排名，和实际收益排名有多像？</p><p>这就是 <strong>IC（Information Coefficient，信息系数）</strong> 的核心思想。打个比方——IC 就像考试估分准不准：你预估的前 5 名跟实际前 5 名的重合度越高，说明你的判断越靠谱。</p><p>计算方法：每一期，把所有标的按因子值排名，再按下一期的实际收益排名，然后算两个排名的 Spearman 相关系数。Spearman 是相关系数的一种，专门看排名而不是数值——就像比较两次考试的“班级第几名”是否一致，而不是看具体分数。相关系数范围从 -1 到 +1：+1 表示因子排名和收益排名完全一致（完美预测），-1 表示完全相反，0 表示毫无关系。</p><p><strong>IC 均值</strong>是多期 IC 的平均值，反映因子是否长期有效：</p><ul><li>绝对值 &gt; 0.03：有一定参考价值</li><li>绝对值 &gt; 0.05：算不错的因子</li><li>绝对值 &gt; 0.1：非常强的因子（实际中很罕见）</li></ul><p><strong>ICIR（IC 信息比率）</strong> = IC 均值 / IC 标准差，衡量 IC 的稳定性。不仅要均值高，还要稳定（偶尔猜中一次的因子不算好，每年都稳定有效才算）——类似夏普比率的思路。</p><h3 id="动手实验-1-gdp-因子-ic-分析" tabindex="-1">动手实验 1：GDP 因子 IC 分析 <a class="header-anchor" href="#动手实验-1-gdp-因子-ic-分析" aria-label="Permalink to &quot;动手实验 1：GDP 因子 IC 分析&quot;">​</a></h3><p>我们一起把这份 spec 写出来。这次重点看两件新东西：<strong>评估工具先讲清楚再用</strong>，以及<strong>因子计算的关键参数要点名到函数级</strong>。</p><h4 id="起草上下文-任务" tabindex="-1">起草上下文 + 任务 <a class="header-anchor" href="#起草上下文-任务" aria-label="Permalink to &quot;起草上下文 + 任务&quot;">​</a></h4><p>这是收官章第一份 spec，承接前八章的所有实验。上下文段把“学员已经在用因子但没意识到”这个起点交代清楚：</p><blockquote><p><strong>上下文</strong>：学员已完成第二至八章。本 spec 对应 notebook <code>q9-daily-work.ipynb</code> 的 Step 1，从零引入因子概念和 IC 评估方法，并用 10 国 GDP 数据做第一个因子评估实验。</p><p><strong>任务</strong>：在 notebook 中创建 Step 1 的所有单元格——导入库、因子回顾表、IC 方法说明、GDP 因子 IC 实验、排名对比图、GDP 分析、因子分类全景表。</p></blockquote><blockquote><p>📌 <strong>要点</strong>：收官章 spec 把“评估工具”前置于“评估实验”。要求段先单独要求一个 IC 方法说明 markdown（讲 Spearman、阈值、ICIR），再要求 GDP 实验——把全章共用的“测量尺”先建起来，后面所有 spec 都引用同一套语言。</p></blockquote><h4 id="起草要求-函数签名精确-参数全显式" tabindex="-1">起草要求：函数签名精确 + 参数全显式 <a class="header-anchor" href="#起草要求-函数签名精确-参数全显式" aria-label="Permalink to &quot;起草要求：函数签名精确 + 参数全显式&quot;">​</a></h4><p>要求段是这份 spec 最长的一节（11 条）。两个最关键的细节：</p><blockquote><p><strong>要求</strong>（摘要）：前两条规定整体结构，3-5 条是具体的 oxq 模块调用细节。</p><ol><li>IC 方法说明 markdown 必须放在 GDP 实验之前——先讲 Spearman 相关系数、IC 阈值（0.03 / 0.05 / 0.1）、ICIR 概念</li><li>GDP 数据下载用 <code>WorldBankFetcher()</code> + <code>FactorDownloader(fetcher, sub=&quot;macro&quot;)</code> + <code>dl.download(&quot;gdp&quot;, start=&quot;2010&quot;, end=&quot;2024&quot;, countries=countries)</code></li><li>ETF 价格用 <code>YFinanceDownloader()</code> + <code>LocalMarketDataProvider().get_bars()</code>，时间范围 2011-01-01 至 2026-12-31</li><li>IC 计算：每个“因子年→收益年”配对，用 <code>scipy.stats.spearmanr</code> 算相关系数；同时跑 GDP 总量因子和 GDP 增速因子（<code>gdp_df.pct_change()</code>）</li><li>视觉契约：1×2 柱状图（figsize 14×5），正相关蓝色、负相关红色，加 IC 均值虚线；slope chart 选 IC 最大那一年，中美红色粗线高亮、其他灰色</li></ol></blockquote><blockquote><p>📌 <strong>要点</strong>：量化研究 spec 必须把“算什么”具体到函数。“算 IC”不够——<code>spearmanr</code> 还是 <code>pearsonr</code>？前者看排名相关、后者看数值相关，因子评估默认用 spearman。<strong>任何统计计算都要点名具体函数，避免 AI 在等价函数间随机选。</strong></p></blockquote><blockquote><p>📌 <strong>要点</strong>：复用现成模块时，spec 第一条要点名所有 import 路径——AI 不知道哪些轮子已经存在，名字写错就重复造轮子。本节涉及 <code>WorldBankFetcher</code>、<code>FactorDownloader</code>、<code>read_factor</code>、<code>Momentum</code>、<code>RollingVolatility</code> 等 7 个模块，全部按官方写法显式列出。</p></blockquote><h4 id="起草结果呈现" tabindex="-1">起草结果呈现 <a class="header-anchor" href="#起草结果呈现" aria-label="Permalink to &quot;起草结果呈现&quot;">​</a></h4><blockquote><p><strong>结果呈现</strong>：GDP 数据表（万亿美元） + 10 国 ETF 覆盖表 + 1×2 IC 柱状图 + IC 均值/ICIR 打印 + 排名对比 slope chart + GDP 分析 markdown + 6 类因子分类全景表 + 过渡文案。</p></blockquote><p>完整 spec 在 <a href="https://github.com/xingwudao/xquant-learning/blob/main/q9-daily-work/specs/spec-01-factor-intro.md" target="_blank" rel="noreferrer"><code>specs/spec-01-factor-intro.md</code></a>——复制给 AI，弹窗选「允许」。</p><p>AI 助手执行完毕后，你的 notebook 里应该出现了 GDP 数据表、IC 柱状图和排名对比图。</p><p>这个实验做了什么？先下载 10 个国家的 GDP 数据和对应的指数 ETF 价格数据，然后分别用两个 GDP 因子（总量和增速）来预测下一年的指数收益排名，计算每一年的 IC。</p><h3 id="运行结果" tabindex="-1">运行结果 <a class="header-anchor" href="#运行结果" aria-label="Permalink to &quot;运行结果&quot;">​</a></h3><p>先看两个因子的 IC 对比，如图 9-1 所示。</p><p><img src="'+d+'" alt="GDP 总量因子和增速因子的年度 IC 对比"></p><p>GDP 总量因子：IC 均值 = 0.1272，ICIR = 0.3158。GDP 增速因子：IC 均值 = -0.0390，ICIR = -0.1177。</p><p>GDP 总量因子的 IC 均值为正，说明 GDP 越大的国家，下一年股市表现确实有略好的倾向。虽然很弱、不稳定，但方向是对的。这就呼应了第二章的选择逻辑——我们根据 GDP 总量挑选了最大的两个经济体（中国和美国），用沪深 300 和纳斯达克来构建候选池，背后是有数据支撑的。</p><p>而 GDP 增速因子的 IC 更差，说明“增长快”并不能预测“股市涨得好”——经济增速和股市回报的关系比直觉想的要弱得多。</p><p>再看 IC 最高那一年的排名对比图，如图 9-2 所示。</p><p><img src="'+n+'" alt="IC 最高年份的 GDP 排名 vs 收益排名对比"></p><p>左列是 GDP 总量排名，右列是下一年指数收益排名。线越平，说明两个排名越接近（IC 越高）；线交叉越多说明排名差异大（IC 低）。中美两国用红色高亮——你能直观感受到“IC 高”意味着什么。</p><h3 id="结果解读" tabindex="-1">结果解读 <a class="header-anchor" href="#结果解读" aria-label="Permalink to &quot;结果解读&quot;">​</a></h3><p>GDP 因子的局限很明显：年度数据、10 个国家、十几年样本，IC 估计噪音很大。但这正好说明了 IC 的价值——不是拍脑袋觉得“有道理”就行，要用数据验证。</p><h3 id="因子的分类" tabindex="-1">因子的分类 <a class="header-anchor" href="#因子的分类" aria-label="Permalink to &quot;因子的分类&quot;">​</a></h3><p>因子的世界远不止 GDP 和动量。主要的因子类别如表 9-3 所示，也是你未来挖掘新因子的方向。</p><p><strong>表 9-3 因子分类全景</strong></p><table tabindex="0"><thead><tr><th>因子类别</th><th>含义（一句话）</th><th>常见例子</th><th>数据来源</th></tr></thead><tbody><tr><td>价值</td><td>便不便宜</td><td>市盈率、市净率</td><td>财报数据</td></tr><tr><td>动量</td><td>涨跌趋势</td><td>N 日收益率、风险调整动量</td><td>价格数据</td></tr><tr><td>质量</td><td>公司好不好</td><td>利润率、负债率</td><td>财报数据</td></tr><tr><td>波动率</td><td>稳不稳</td><td>历史波动率</td><td>价格数据</td></tr><tr><td>宏观</td><td>大环境</td><td>GDP、利率</td><td>经济数据</td></tr><tr><td>另类</td><td>非传统信息</td><td>新闻情绪、卫星图像</td><td>另类数据</td></tr></tbody></table><p>前面课程里我们用过宏观因子（GDP）和动量因子（风险调整动量）。接下来我们重点研究动量因子——因为它用的是每天都有的价格数据，样本量大、更新快，最适合日常研究。</p><p>GDP 因子受限于年度频率和小样本，IC 很不稳定。接下来，我们用日频价格数据、更多标的来评估动量因子——这才是量化研究员的日常节奏。</p><hr><h2 id="_9-2-动量因子——涨得好的会继续涨吗" tabindex="-1">9.2 动量因子——涨得好的会继续涨吗？ <a class="header-anchor" href="#_9-2-动量因子——涨得好的会继续涨吗" aria-label="Permalink to &quot;9.2 动量因子——涨得好的会继续涨吗？&quot;">​</a></h2><p>第三章里我们用动量排名来决定买多少——涨得好的多买，跌的不买。当时在 3 只标的上回测效果不错。</p><p>但那只是 3 只标的。动量因子在更大范围内真的有效吗？它在什么环境下会失灵？要回答这些问题，我们需要扩大标的池，用 IC 来严格评估。</p><h3 id="动手实验-2-动量因子-ic-分析" tabindex="-1">动手实验 2：动量因子 IC 分析 <a class="header-anchor" href="#动手实验-2-动量因子-ic-分析" aria-label="Permalink to &quot;动手实验 2：动量因子 IC 分析&quot;">​</a></h3><p>我们一起把这份 spec 写出来。这次重点看两件新东西：<strong>IC 计算函数的签名要点名到参数</strong>，以及<strong>最低样本数阈值要写明白</strong>。</p><h4 id="起草上下文-任务-1" tabindex="-1">起草上下文 + 任务 <a class="header-anchor" href="#起草上下文-任务-1" aria-label="Permalink to &quot;起草上下文 + 任务&quot;">​</a></h4><blockquote><p><strong>上下文</strong>：在 <code>q9-daily-work.ipynb</code> 的 Step 1 中已完成库导入和 GDP 因子 IC 实验。已有变量 <code>downloader</code>（YFinanceDownloader）、<code>provider</code>（LocalMarketDataProvider）。本 spec 对应 Step 2，把标的池从 10 只扩展到 25 只，用日频数据做动量因子的 IC 分析。</p><p><strong>任务</strong>：在 notebook 中新建 Step 2 的所有单元格——构建 25 只标的池、计算动量因子与前向收益、IC 分析表和图、按波动率分组的 IC 分析、问题总结。</p></blockquote><h4 id="起草要求-函数签名-最低样本阈值" tabindex="-1">起草要求：函数签名 + 最低样本阈值 <a class="header-anchor" href="#起草要求-函数签名-最低样本阈值" aria-label="Permalink to &quot;起草要求：函数签名 + 最低样本阈值&quot;">​</a></h4><p>要求段的灵魂是把 IC 计算的“工程化模式”用函数签名固化下来——任何新因子来了都按这个模板跑一遍。</p><blockquote><p><strong>要求</strong>（摘要）：</p><ol><li>25 只标的池：22 国 ETF + 3 个大宗商品（GLD / USO / SLV），时间范围 2015-01-01 至 2025-12-31</li><li>因子矩阵：<code>Momentum().compute(df, column=&quot;close&quot;, period=20)</code>、<code>RollingVolatility().compute(df, column=&quot;close&quot;, period=20)</code>、RAM = 动量 / 波动率</li><li>前向收益窗口 <code>[10, 20, 40]</code> 交易日：<code>df[&quot;close&quot;].pct_change(h).shift(-h)</code></li><li>实现 <code>compute_ic_series(factor_df, fwd_df, min_assets=5)</code>：每个交易日取因子值和前向收益的交集标的（至少 min_assets 个），用 Spearman 算 IC</li><li>实现 <code>compute_grouped_ic(factor_df, fwd_df, vol_df, min_assets=6)</code>：每天按波动率中位数把标的分高/低两组，组内分别算 Spearman IC；要求交集 ≥12、每组 ≥ min_assets</li><li>视觉契约：2×3 子图（figsize 18×8），柱状图 <code>width=2, alpha=0.2, steelblue</code> + 60 日滚动均值 <code>darkblue</code> + IC 均值红色虚线</li><li>末尾保留 <code>ic_ts = ic_results[&quot;风险调整动量 → 20日&quot;]</code> 和 <code>fwd_df = fwd_dfs[20]</code> 给 spec-03</li></ol></blockquote><blockquote><p>📌 <strong>要点</strong>：IC 计算这种“对每天做一次统计、跳过样本不足的天、收集成时间序列”的工程化模式，必须封装成函数——<code>compute_ic_series(factor_df, fwd_df, min_assets=5)</code>。函数签名级精度让 AI 没有自由发挥空间，也让学员未来换标的池时有明确的修改入口。</p></blockquote><blockquote><p>📌 <strong>要点</strong>：统计计算的阈值要写明白。<code>min_assets=5</code>（整体 IC）和 <code>min_assets=6</code>（分组 IC，配合交集 ≥12 的额外门槛）不是凭空选——Spearman 在 ≥5 时方差才可控，分组样本减半后 ≥6 才能稳定。<strong>任何“最少多少样本”的阈值都要进 spec 的参数清单，否则 AI 可能选 3 也可能选 10。</strong></p></blockquote><h4 id="起草结果呈现-1" tabindex="-1">起草结果呈现 <a class="header-anchor" href="#起草结果呈现-1" aria-label="Permalink to &quot;起草结果呈现&quot;">​</a></h4><blockquote><p><strong>结果呈现</strong>：25 只标的覆盖表 + 动量因子矩阵 + 6 组 IC 对比表 + 2×3 IC 时间序列子图 + 分组 IC 表 + 高/低波动 IC 时间序列对比图 + 问题总结 markdown。</p></blockquote><p>完整 spec 在 <a href="https://github.com/xingwudao/xquant-learning/blob/main/q9-daily-work/specs/spec-02-momentum-ic.md" target="_blank" rel="noreferrer"><code>specs/spec-02-momentum-ic.md</code></a>——复制给 AI，弹窗选「允许」。</p><p>AI 助手执行完毕后，你的 notebook 里应该出现了 25 只标的的覆盖表、IC 对比表和多张 IC 时间序列图。</p><p>这个实验做了什么？把标的池从 第二、三章 的 3 只扩展到 25 只全球 ETF（22 个国家/地区 + 黄金/原油/白银），用 2015-2025 的日频数据，分别测试两个动量因子（20 日动量和风险调整动量）在三个前向收益窗口（10/20/40 交易日）上的 IC 表现。然后按每只标的自身的波动率分组，看动量因子在高波动和低波动标的上的表现差异。</p><h3 id="运行结果-1" tabindex="-1">运行结果 <a class="header-anchor" href="#运行结果-1" aria-label="Permalink to &quot;运行结果&quot;">​</a></h3><p>两个动量因子在三个前向窗口上的 IC 对比如表 9-4 所示。</p><p><strong>表 9-4 两个动量因子 × 三个前向窗口的 IC 对比</strong></p><table tabindex="0"><thead><tr><th>因子 —— 前向窗口</th><th>IC 均值</th><th>IC 标准差</th><th>ICIR</th><th>IC&gt;0</th></tr></thead><tbody><tr><td>20日动量 —— 10日</td><td>-0.0263</td><td>0.2794</td><td>-0.0941</td><td>45.7%</td></tr><tr><td>20日动量 —— 20日</td><td>-0.0290</td><td>0.2731</td><td>-0.1062</td><td>45.7%</td></tr><tr><td>20日动量 —— 40日</td><td>-0.0436</td><td>0.2794</td><td>-0.1560</td><td>43.4%</td></tr><tr><td>风险调整动量 —— 10日</td><td>-0.0161</td><td>0.2730</td><td>-0.0589</td><td>46.0%</td></tr><tr><td>风险调整动量 —— 20日</td><td>-0.0193</td><td>0.2705</td><td>-0.0714</td><td>46.4%</td></tr><tr><td>风险调整动量 —— 40日</td><td>-0.0335</td><td>0.2770</td><td>-0.1208</td><td>45.7%</td></tr></tbody></table><p>两个因子在三个窗口上的 IC 均值都接近零——动量因子的截面预测能力很弱。</p><p>2×3 的 IC 时间序列图如图 9-3 所示。</p><p><img src="'+s+'" alt="两个动量因子 × 三个前向收益窗口 IC 对比"></p><p>图 9-3 每个格子是一个“因子 × 前向窗口”组合的 IC 随时间变化。蓝色柱子是每日 IC，深蓝线是 60 日滚动均值，红色虚线是 IC 均值。可以看到 IC 在零附近大幅波动，正负交替——说明动量因子的预测能力非常不稳定。</p><p>关键发现来自<strong>按波动率分组的 IC 分析</strong>——按标的自身波动率分组的 IC 表现如表 9-5 所示。</p><p><strong>表 9-5 动量因子在高波动 vs 低波动标的上的 IC 表现</strong></p><table tabindex="0"><thead><tr><th>因子</th><th>整体 IC</th><th>高波动组 IC</th><th>低波动组 IC</th><th>Spread</th></tr></thead><tbody><tr><td>20日动量</td><td>-0.0290</td><td>-0.0334</td><td>-0.0119</td><td>0.0215</td></tr><tr><td>风险调整动量</td><td>-0.0193</td><td>-0.0354</td><td>-0.0011</td><td>0.0343</td></tr></tbody></table><p>直观对比如图 9-4 所示。</p><p><img src="'+l+'" alt="风险调整动量因子：高波动 vs 低波动标的 IC 对比"></p><h3 id="结果解读-1" tabindex="-1">结果解读 <a class="header-anchor" href="#结果解读-1" aria-label="Permalink to &quot;结果解读&quot;">​</a></h3><p>分组分析揭示了一个重要规律：<strong>同一天内，高波动标的的动量 IC 明显差于低波动标的</strong>。</p><p>波动率大的资产，价格噪音更大，动量信号就更容易被噪音淹没，指错方向。风险调整动量（RAM = 动量 / 波动率）在低波动组表现更好，说明除以波动率确实有帮助——但对高波动标的依然救不了。</p><p>结论：<strong>一个因子不够</strong>。动量因子在高波动环境下失灵，我们需要补充能感知波动率环境的因子，在高波动时调整策略行为。</p><hr><h2 id="_9-3-从因子到策略——让数据说话" tabindex="-1">9.3 从因子到策略——让数据说话 <a class="header-anchor" href="#_9-3-从因子到策略——让数据说话" aria-label="Permalink to &quot;9.3 从因子到策略——让数据说话&quot;">​</a></h2><p>我们已经知道了动量因子的弱点。现在的问题是：这个发现能不能帮我们改进策略？</p><h3 id="动手实验-3-补充因子-策略改进" tabindex="-1">动手实验 3：补充因子 + 策略改进 <a class="header-anchor" href="#动手实验-3-补充因子-策略改进" aria-label="Permalink to &quot;动手实验 3：补充因子 + 策略改进&quot;">​</a></h3><p>我们一起把这份 spec 写出来。这次重点看两件新东西：<strong>用包装类把因子的弱点翻译成过滤规则</strong>，以及<strong>教学简化声明</strong>——哪些参数是为了演示效果而非工程最优。</p><h4 id="起草上下文-任务-2" tabindex="-1">起草上下文 + 任务 <a class="header-anchor" href="#起草上下文-任务-2" aria-label="Permalink to &quot;起草上下文 + 任务&quot;">​</a></h4><blockquote><p><strong>上下文</strong>：在 <code>q9-daily-work.ipynb</code> 的 Step 2 中已完成 25 只标的的动量因子 IC 分析和分组分析。已有变量：<code>all_data</code>、<code>vol_df</code>、<code>fwd_dfs</code>、<code>ic_results</code>、<code>compute_ic_series</code> 函数、<code>downloader</code>。本 spec 对应 Step 3——补充因子、总结发现、改进策略并回测对比。</p><p><strong>任务</strong>：在 notebook 中新建 Step 3 的所有单元格——补充因子 IC、因子评估发现、策略改进框架、第三章三只标的基准回测、波动率过滤改进、对比分析。</p></blockquote><h4 id="起草要求-包装类-教学简化声明" tabindex="-1">起草要求：包装类 + 教学简化声明 <a class="header-anchor" href="#起草要求-包装类-教学简化声明" aria-label="Permalink to &quot;起草要求：包装类 + 教学简化声明&quot;">​</a></h4><p>要求段把“研究 → 工程”这条路具象化：因子评估发现“动量在高波动时容易出错”，怎么把这个发现翻译成代码里能跑的过滤规则？答案是<strong>包装一个 optimizer</strong>——保留原 optimizer 的所有行为，只在末尾“打补丁”。</p><blockquote><p><strong>要求</strong>（摘要）：</p><ol><li>补充因子 IC：复用 <code>vol_df</code>（波动率因子）+ 新建 <code>rev_df = -df[&quot;close&quot;].pct_change(5)</code>（短期反转因子），用 <code>compute_ic_series</code> 算 20 日前向 IC，三因子对比表</li><li>第三章三只标的（510300.SS / 513100.SS / 518880.SS）+ 基准策略：<code>Threshold</code> 信号、<code>TopNRankingOptimizer(score_col=&quot;ram&quot;, n=3, filter_negative=True)</code>、<code>RebalanceFrequencyRule(interval_days=21)</code>、data_start=“2020-06-01”</li><li>实现 <code>VolFilteredOptimizer</code> 包装类：接受 <code>base_optimizer</code>、<code>vol_threshold</code>、<code>market_vol</code> 参数；<code>optimize()</code> 先调用 base 拿到权重、再从 indicators 取最新日期查 market_vol、若 &gt; 阈值则把所有持仓权重减半、多余分配给 CASH；暴露 <code>name</code> 和 <code>required_indicators</code></li><li>阈值取市场平均波动率的中位数（教学场景刻意“过滤狠”——50% 时间减仓，让对比效果显著）</li><li>视觉契约：净值曲线对比图（figsize 14×7），基准蓝 #3498DB、过滤橙 #E67E22，归一化到起点 = 100，图例标注夏普比率</li></ol></blockquote><blockquote><p>📌 <strong>要点</strong>：把研究发现的因子弱点翻译成代码里的过滤规则时，首选<strong>包装一个新类</strong>——保留原 optimizer 的所有行为，只在末尾“打补丁”。这样原 optimizer 不动、新行为可插可拔，未来想换过滤逻辑只换包装。</p><p>📌 <strong>要点</strong>：包装类要复用原类的契约接口——<code>VolFilteredOptimizer</code> 接收一个 <code>base_optimizer</code> 引用，复用它的 <code>required_indicators</code>，只在 <code>optimize()</code> 末尾插入波动率检查。这样调用方完全感知不到差别，可以无痛切换。</p></blockquote><blockquote><p>📌 <strong>要点</strong>：教学场景的参数选择必须在 spec 里声明“是简化、不是最优”。波动率阈值取中位数（50% 时间减仓）、仓位减半（不是 0.7× 也不是 0.3×）——都是为了让对比效果显著的教学选择。<strong>spec 写明这一点，学员仿写时才知道哪些数字可以、应该被改。</strong></p></blockquote><h4 id="起草结果呈现-2" tabindex="-1">起草结果呈现 <a class="header-anchor" href="#起草结果呈现-2" aria-label="Permalink to &quot;起草结果呈现&quot;">​</a></h4><blockquote><p><strong>结果呈现</strong>：三因子 IC 对比表 + 因子评估发现 markdown + 策略改进方向 markdown + 第三章三只标的覆盖信息 + 基准回测指标 + 阈值与高波动天数占比 + 过滤策略回测指标 + 指标对比表 + 净值曲线对比图 + 动态分析文本 + 小结 markdown。</p></blockquote><p>完整 spec 在 <a href="https://github.com/xingwudao/xquant-learning/blob/main/q9-daily-work/specs/spec-03-factor-to-strategy.md" target="_blank" rel="noreferrer"><code>specs/spec-03-factor-to-strategy.md</code></a>——复制给 AI，弹窗选「允许」。</p><p>AI 助手执行完毕后，你的 notebook 里应该出现了三因子 IC 对比表、基准策略和波动率过滤策略的回测结果，以及净值曲线对比图。</p><p>这个实验做了什么？分三步走：</p><ol><li><strong>补充因子</strong>：在 25 只 ETF 上计算波动率因子和短期反转因子的 IC，与动量因子对比</li><li><strong>基准回测</strong>：回到第三章的三只标的（沪深300、纳指100、黄金），用 oxq 复刻第三章的动量排名策略作为基准</li><li><strong>改进回测</strong>：基于因子评估的发现（高波动时动量预测力下降），给策略加上波动率过滤——高波动时自动降低仓位</li></ol><h3 id="运行结果-2" tabindex="-1">运行结果 <a class="header-anchor" href="#运行结果-2" aria-label="Permalink to &quot;运行结果&quot;">​</a></h3><p>三因子在 25 只 ETF、20 日前向窗口上的 IC 对比如表 9-6 所示。</p><p><strong>表 9-6 三因子 IC 对比（25 只 ETF，20 日前向窗口）</strong></p><table tabindex="0"><thead><tr><th>因子</th><th>IC 均值</th><th>IC 标准差</th><th>ICIR</th><th>IC&gt;0</th></tr></thead><tbody><tr><td>风险调整动量</td><td>-0.0193</td><td>0.2705</td><td>-0.0714</td><td>46.4%</td></tr><tr><td>波动率</td><td>0.0020</td><td>0.2643</td><td>0.0076</td><td>49.1%</td></tr><tr><td>短期反转</td><td>0.0183</td><td>0.2786</td><td>0.0659</td><td>52.6%</td></tr></tbody></table><p>三个因子各有侧重——动量看趋势、波动率看风险、反转看短期超跌。它们在不同环境下各有优势。</p><h3 id="因子评估的发现" tabindex="-1">因子评估的发现 <a class="header-anchor" href="#因子评估的发现" aria-label="Permalink to &quot;因子评估的发现&quot;">​</a></h3><p>关键发现是：<strong>动量因子在高波动标的上 IC 为负，在低波动标的上接近零</strong>——波动率是动量因子失灵的主要原因。这个发现直接指向一个改进方向：在使用动量因子做决策时，应该考虑波动率环境。</p><h3 id="因子评估的发现能改进策略吗" tabindex="-1">因子评估的发现能改进策略吗？ <a class="header-anchor" href="#因子评估的发现能改进策略吗" aria-label="Permalink to &quot;因子评估的发现能改进策略吗？&quot;">​</a></h3><p>我们在 25 只 ETF 上做了因子评估，现在回到 第二、三章 的三只标的（沪深300、纳指100、黄金），看看这些发现能不能改进策略。</p><p>回顾一下贯穿全书的两层选择框架：</p><ul><li><strong>第一层：GDP 因子选候选池</strong>——在 Step 1 中，GDP 因子帮我们从全球市场中筛出了有潜力的国家/资产类别</li><li><strong>第二层：动量因子做择时</strong>——在候选池内，用动量排名决定买谁、买多少</li></ul><p>因子评估告诉我们，动量在高波动时容易出错。如果我们能让策略在高波动时自动降低仓位，应该能改善表现。</p><p>基准策略与改进策略的回测对比如表 9-7 所示。</p><p><strong>表 9-7 基准（动量排名）vs 改进（波动率过滤）策略对比</strong></p><table tabindex="0"><thead><tr><th>策略</th><th>累计收益</th><th>年化波动率</th><th>最大回撤</th><th>夏普比率</th></tr></thead><tbody><tr><td>基准（动量排名）</td><td>+113.36%</td><td>15.01%</td><td>-13.32%</td><td>1.09</td></tr><tr><td>改进（波动率过滤）</td><td>+92.96%</td><td>11.00%</td><td>-10.17%</td><td>1.25</td></tr></tbody></table><p>净值曲线对比如图 9-5 所示。</p><p><img src="'+p+'" alt="因子评估 —— 策略改进：基准 vs 波动率过滤"></p><p>基准策略夏普 1.09，最大回撤 -13.32%。波动率过滤后夏普 1.25，最大回撤 -10.17%，回撤改善 23.7%。因子评估告诉我们「高波动时动量 IC 翻负」，加上波动率过滤后回撤确实下降了——这就是因子评估带来的 Alpha，不是靠猜，而是靠数据发现问题、改进策略。</p><h3 id="结果解读-2" tabindex="-1">结果解读 <a class="header-anchor" href="#结果解读-2" aria-label="Permalink to &quot;结果解读&quot;">​</a></h3><p>波动率过滤带来了明显的改善：夏普比率从基准的 1.09 提升到 1.25，最大回撤从 -13.3% 降低到 -10.2%——回撤改善了约 24%。</p><p>代价是什么？累计收益从 113% 降到了 93%——高波动时降仓位，自然少赚了一些。但风险调整后的收益（夏普）更好了。这正是因子评估带来的价值：<strong>不是让你赚更多，而是让你在承担同样风险的情况下赚得更稳</strong>。</p><p>这个改进不是靠猜测，而是因子评估告诉我们的——IC 分析发现高波动时动量 IC 翻负，我们据此加了波动率过滤，回测验证了确实有效。这就是因子研究带来的 Alpha。</p><hr><h2 id="_9-4-量化交易员的一周长什么样" tabindex="-1">9.4 量化交易员的一周长什么样 <a class="header-anchor" href="#_9-4-量化交易员的一周长什么样" aria-label="Permalink to &quot;9.4 量化交易员的一周长什么样&quot;">​</a></h2><p>到这里你已经掌握了“找因子 → 评估 → 改进策略”的完整流程。但每天打开电脑，到底先做什么、再做什么？光知道“应该会做”还不够，章名《量化交易员的日常工作》得给你一份能打印贴在桌面的作业日历。</p><p>把前八章的动作串成一条<strong>可执行的研究流</strong>——一个量化交易员典型的一周长什么样：</p><h3 id="每个交易日-≤-30-分钟" tabindex="-1">每个交易日（≤ 30 分钟） <a class="header-anchor" href="#每个交易日-≤-30-分钟" aria-label="Permalink to &quot;每个交易日（≤ 30 分钟）&quot;">​</a></h3><p><strong>开盘前（5 分钟）。</strong> 看一眼策略的实盘运行状态。监控仪表盘（第八章 Step 1）告诉你“是不是坏了”——滚动夏普还在 0 以上吗？回撤超过你预设的阈值了吗？相对沪深300超额收益还为正吗？三个指标全绿，今天没事；任意一个亮红灯，列入待诊断清单。</p><p><strong>盘后（10-15 分钟）。</strong> 拉今日的成交回报，跑一次执行对账（第七章 Step 4）——回测口径下应该成交什么、实盘实际成交了什么、滑点和佣金加起来是不是在你的预算内。差距稳定 = 健康；差距突然放大 → 列入待诊断清单。</p><p><strong>晚间（10 分钟）。</strong> 把今天的关键事件写进迭代记录表（第八章 Step 3）。“今天恶化时段触发”、“某只 ETF 触发止损”、“市场状态切到高波动”——三个月后这张表是你最值钱的资产。</p><h3 id="每周-2-3-小时-建议周末" tabindex="-1">每周（2-3 小时，建议周末） <a class="header-anchor" href="#每周-2-3-小时-建议周末" aria-label="Permalink to &quot;每周（2-3 小时，建议周末）&quot;">​</a></h3><p><strong>周一上午：监控扫描 + 诊断分流。</strong> 把过去一周的滚动夏普、回撤、超额收益拉出来，对比上周——稳定还是恶化？如果有恶化时段，跑诊断三问（第八章 Step 2）：先排执行落差（外）、再查市场状态（中）、最后看策略本身（内）。</p><p><strong>周末半天：因子探索 / 假设实验。</strong> 两种典型节奏二选一：</p><ul><li><strong>因子探索（第九章流程）</strong>：观察市场最近的特征 → 提一个新因子假设 → 跑 IC + 分组分析 → 决定是否纳入策略候选池。</li><li><strong>假设驱动实验（第八章 Step 3）</strong>：写下假设和验证标准 → 跑对照回测 → 看结果确认还是推翻假设。<strong>纪律：标准定下来就不能事后改。</strong></li></ul><h3 id="每月-半天" tabindex="-1">每月（半天） <a class="header-anchor" href="#每月-半天" aria-label="Permalink to &quot;每月（半天）&quot;">​</a></h3><p><strong>月度复盘。</strong> 拉本月的全部迭代记录，问三个问题：①假设确认率多少？②哪些假设被推翻、原因是什么？③下个月的研究方向？复盘的目的不是论功行赏，是让“疑”持续运转——上个月你以为对的东西，本月数据是不是还支持？</p><p><strong>工具升级。</strong> 数据源更新了吗？open-xquant 有新模块要试吗？哪条 spec 你写第三遍了——可以模板化吗？这一步是给“做”持续松绑——让单位时间能做的实验更多。</p><h3 id="每季度-1-2-天" tabindex="-1">每季度（1-2 天） <a class="header-anchor" href="#每季度-1-2-天" aria-label="Permalink to &quot;每季度（1-2 天）&quot;">​</a></h3><p><strong>季度策略检阅（第五 + 六章工具全用上）。</strong> 跑一次完整的策略体检：基准对比、分年拆解、收益分布、参数敏感性、Walk-forward、交叉验证、规则负担——五把铲子（含第五章敏感性）每把都挥一次。任意一项亮红灯，启动重新设计或退役流程。</p><p><strong>视野扩展。</strong> 读 1-2 篇论文 / 行业报告 / 优秀公开策略——不是为了立刻抄，是为了看看世界变到哪了。一个量化交易员退化的标志，是他几个月没读过任何外部输入。</p><h3 id="一张可贴桌面的作业速查" tabindex="-1">一张可贴桌面的作业速查 <a class="header-anchor" href="#一张可贴桌面的作业速查" aria-label="Permalink to &quot;一张可贴桌面的作业速查&quot;">​</a></h3><p>把上面的节奏压成一张速查表，对应飞轮和三字要点的位置如表 9-8 所示。</p><p><strong>表 9-8 量化交易员的作业速查</strong></p><table tabindex="0"><thead><tr><th>周期</th><th>主要动作</th><th>飞轮位置</th><th>三字要点</th></tr></thead><tbody><tr><td>每日</td><td>监控仪表盘 + 执行对账 + 写迭代记录</td><td>归因层 + 执行层</td><td>看</td></tr><tr><td>每周</td><td>监控扫描 + 诊断分流 + 因子/假设实验</td><td>归因层 + 候选/组合层</td><td>看 + 疑 + 做</td></tr><tr><td>每月</td><td>月度复盘 + 工具升级</td><td>归因层（反哺起点）</td><td>疑 + 做</td></tr><tr><td>每季度</td><td>五把铲子全检阅 + 视野扩展</td><td>全飞轮</td><td>做 + 看 + 疑</td></tr></tbody></table><p><strong>节奏比“努力”重要。</strong> 量化不是靠加班赚钱——是靠<strong>让飞轮持续转、让坏假设尽早被推翻、让好假设尽快上线</strong>。一周一次因子实验、一个月一次复盘、一个季度一次大检阅——只要持续做，三年后的你会让现在的你认不出来。</p><hr><h2 id="_9-5-本章总结" tabindex="-1">9.5 本章总结 <a class="header-anchor" href="#_9-5-本章总结" aria-label="Permalink to &quot;9.5 本章总结&quot;">​</a></h2><h3 id="策略进化路径" tabindex="-1">策略进化路径 <a class="header-anchor" href="#策略进化路径" aria-label="Permalink to &quot;策略进化路径&quot;">​</a></h3><p>三步走，每一步都有明确的产出：</p><ul><li><strong>Step 1</strong>：因子概念 + IC 评估方法（从直觉到数据验证）</li><li><strong>Step 2</strong>：动量因子 IC 分析（发现高波动是弱点）</li><li><strong>Step 3</strong>：因子评估改进策略（波动率过滤提升夏普）</li></ul><h3 id="概念速查表" tabindex="-1">概念速查表 <a class="header-anchor" href="#概念速查表" aria-label="Permalink to &quot;概念速查表&quot;">​</a></h3><p>本章涉及的核心概念汇总如表 9-9 所示，方便随时回查。</p><p><strong>表 9-9 第九章核心概念速查</strong></p><table tabindex="0"><thead><tr><th>概念</th><th>含义</th><th>类比</th></tr></thead><tbody><tr><td>因子（Factor）</td><td>用来预测资产收益的数据指标</td><td>挑餐厅时看的评分、距离、价格</td></tr><tr><td>IC（信息系数）</td><td>因子排名和收益排名的相似度，衡量因子预测能力</td><td>考试预测分和实际分的排名对比</td></tr><tr><td>ICIR</td><td>IC 均值 / IC 标准差，衡量 IC 的稳定性</td><td>夏普比率的因子版——不仅要准，还要稳</td></tr><tr><td>截面分析</td><td>同一时间点比较不同标的</td><td>同一次考试比较不同学生的成绩</td></tr><tr><td>两层选择框架</td><td>GDP 因子选候选池 + 动量因子做择时</td><td>先选城市（宏观），再选餐厅（微观）</td></tr></tbody></table><h3 id="本章核心认知" tabindex="-1">本章核心认知 <a class="header-anchor" href="#本章核心认知" aria-label="Permalink to &quot;本章核心认知&quot;">​</a></h3><p>走完三个 Step 后，本章最值得带走的三条 q9 独有认知如表 9-10 所示——其余共通认知由 9.6 飞轮 + 三字要点收束。</p><p><strong>表 9-10 第九章核心认知</strong></p><table tabindex="0"><thead><tr><th>认知</th><th>来源</th></tr></thead><tbody><tr><td>波动率是动量因子的关键弱点——高波动标的的 IC 明显更差</td><td>Step 2</td></tr><tr><td>动量因子的截面预测力接近零，回测有效不等于因子有效</td><td>Step 2</td></tr><tr><td>因子评估带来的 Alpha 来自发现因子的弱点，并把弱点转化为过滤规则</td><td>Step 3</td></tr></tbody></table><blockquote><p>本章所有代码的可运行版本见 <code>notebooks/q9-daily-work.ipynb</code></p></blockquote><hr><h2 id="_9-6-写给未来的你" tabindex="-1">9.6 写给未来的你 <a class="header-anchor" href="#_9-6-写给未来的你" aria-label="Permalink to &quot;9.6 写给未来的你&quot;">​</a></h2><p>这是全书的最后一章。回头看看你走过的路——把整本书带给你的东西，浓缩成一张图：<strong>飞轮 + 三字要点 + 一句口号</strong>。</p><p><strong>飞轮的四层你都站过。</strong> 候选层（第二章选 ETF）→ 组合层（第三章定仓位 / 第四章加规则）→ 执行层（第七章下单）→ 归因层（第五、六、八章评估 / 防过拟合 / 监控诊断）→ 这一章的因子研究反过来回到候选与组合层，进入下一圈。这就是“飞轮转完一圈”——每转一圈都比上一圈聪明一点。</p><p><strong>三字要点你都练过。</strong></p><ul><li><strong>做</strong> —— 把动作写成 spec，让 AI 把它变成可重复执行的规则。从第一章的均线、第三章的三种信号、第四章的止损止盈、到第八章的对照实验，每一次都是“做”。</li><li><strong>看</strong> —— 不允许“感觉还行”，所有判断都要落到指标上。年化、波动率、最大回撤、夏普 / 卡玛 / 索提诺、IC、ICIR——你已经收集了一整套尺子。</li><li><strong>疑</strong> —— 永远怀疑你的指标。第一章撞墙、第六章四把铲子、第八章诊断三问、第九章 IC 分组——你已经把“疑”从感觉训练成了流程。</li></ul><p><strong>一句口号你能复述了：「做要规则、看要指标、还要怀疑你的指标。」</strong> 会做、会看，但不会疑，最容易在某些时候把赚到的钱加倍还给市场。这正是为什么“疑”和“做”“看”在本书同等重要。</p><p><strong>你没有写过一行代码</strong>——每一步都是通过撰写清晰的任务说明书（spec），让 AI 来执行。这不是偷懒，这是未来量化的工作方式。<strong>Spec 写作能力本身就是本书最重要的一份带走品</strong>：从第一章的“复制临摹”，到第三、四章的“改参数”，到第六章起的“自己拆四段式”，到第九章的“独立设计研究流程”——你的 spec 能力已经走完了三个台阶。</p><p>量化交易的门槛正在快速降低。以前需要金融学位 + 编程能力 + 大量资金，现在你只需要：清晰的思考 + 数据验证的习惯 + 一个好的 AI 助手。</p><p>但门槛降低不等于赚钱变容易了。市场不会因为工具变好就多给你钱。真正的竞争力在于：</p><ul><li><strong>更好的因子（做）</strong>：别人没发现的数据关系，让“做什么”持续翻新</li><li><strong>更快的迭代（看 + 疑）</strong>：从假设到验证的周期越短越好，让“看 / 疑”快到几乎和市场同步</li><li><strong>更强的纪律（疑）</strong>：不被情绪左右，按数据做决策，不让“疑”被自己的乐观腐蚀</li></ul><p>这三件事，恰好可以交给一个被研究纪律约束好的 AI Agent 去高速放大——具体怎么入门见本章末「拓展阅读」。</p><p><strong>飞轮在你手里——下一圈，让它转得更快、更稳、更聪明。</strong> 祝你在量化的路上走得远。</p><hr><h2 id="拓展阅读" tabindex="-1">拓展阅读 <a class="header-anchor" href="#拓展阅读" aria-label="Permalink to &quot;拓展阅读&quot;">​</a></h2><h3 id="让-agent-替你跑因子研究" tabindex="-1">让 Agent 替你跑因子研究 <a class="header-anchor" href="#让-agent-替你跑因子研究" aria-label="Permalink to &quot;让 Agent 替你跑因子研究&quot;">​</a></h3><p>整章你做的因子研究流程是高度结构化的——找因子、查 IC、看分组、改策略，每一步做什么、看什么指标都有明确标准。<strong>结构化的流程最适合交给 AI Agent 执行。</strong></p><p>但通用 Agent（OpenClaw、Cursor Agent 等）什么都能做但什么都做不精——拿来做量化研究容易跳过 IC 评估、用不可复现的方式处理数据、对 IC=0.01 的因子说“还不错”。这些都是研究纪律问题。</p><p><strong>Harness Engineering（缰绳工程）</strong> —— 给 Agent 装上身份约束、操作流程、工具限制和技能模板，让“什么都能做”变成“按规矩做”。比喻来自驯马：马很强壮但需要缰绳，Agent 能力强但需要研究纪律。</p><h3 id="用-open-xquant-让-agent-接管你的因子研究" tabindex="-1">用 open-xquant 让 Agent 接管你的因子研究 <a class="header-anchor" href="#用-open-xquant-让-agent-接管你的因子研究" aria-label="Permalink to &quot;用 open-xquant 让 Agent 接管你的因子研究&quot;">​</a></h3><p>open-xquant 在 <code>agent/bootstrap/</code> 目录提供了一套量化研究专用的 harness：</p><ul><li><strong>SOUL.md</strong> —— Agent 的身份和底线。最核心的约束是 <strong>“不可复现 = 不可信 = 不可交易”</strong>，通用 Agent 不会自带这条量化纪律</li><li><strong>AGENT.md</strong> —— 研究 SOP（5 阶段：业务约束 → 目标 → 5 要素假设 → 数据准备 → 逐层构建），每一步都要你确认才推进，不会偷跑</li><li><strong>TOOLS.md</strong> —— 工具清单（通过 MCP Server 暴露 62 个 SDK 工具）</li><li><strong>19 个 skill 文件</strong> —— 覆盖从策略构建、因子评估到实盘交易的全流程</li></ul><p><strong>怎么用？</strong> 用 <code>agent/bootstrap/</code> 覆盖 OpenClaw 默认文件 → 让 Agent 自行安装 open-xquant skills → 配置 MCP Server。然后你用自然语言提研究需求，Agent 按 SOP 引导你完成。具体安装步骤见 <a href="https://github.com/xingwudao/open-xquant" target="_blank" rel="noreferrer">open-xquant 仓库</a>。</p><h3 id="更多因子、更复杂的组合——机器学习的入口" tabindex="-1">更多因子、更复杂的组合——机器学习的入口 <a class="header-anchor" href="#更多因子、更复杂的组合——机器学习的入口" aria-label="Permalink to &quot;更多因子、更复杂的组合——机器学习的入口&quot;">​</a></h3><p>本课程只用了三个因子做演示。实际的量化研究中，因子数量可能是几十甚至上百个。当因子多了，手工写 if-else 规则来组合就不现实了——阈值怎么定？因子之间的交互关系怎么处理？</p><p>这时候就需要机器学习：</p><ul><li><strong>决策树 / 随机森林</strong>：自动学习因子之间的分裂规则，可解释性好</li><li><strong>梯度提升树（XGBoost / LightGBM）</strong>：量化行业最常用的多因子组合方法</li><li><strong>神经网络</strong>：能捕捉更复杂的非线性关系，但需要更多数据</li></ul><p>核心思路都一样：把因子当作特征，未来收益当作标签，让模型学出最优的组合方式。这是你未来进入实战后可以深入探索的方向——但本书的主线已经够你跑很久了，<strong>先把第八章的迭代闭环跑顺，再考虑加机器学习</strong>。</p><hr><h2 id="反馈与读者群" tabindex="-1">反馈与读者群 <a class="header-anchor" href="#反馈与读者群" aria-label="Permalink to &quot;反馈与读者群&quot;">​</a></h2><p>如果你发现本章有错别字、概念不清或实验结果不一致，欢迎 <a href="https://github.com/xingwudao/xquant-beginner/issues/new/choose" target="_blank" rel="noreferrer">提交 GitHub Issue</a>。</p><p>课程、正式书和后续更新见 <a href="https://xquant.shop/courses" target="_blank" rel="noreferrer">xquant.shop/courses</a>。</p><p>添加作者微信 <code>xquanter</code> 进入读者群。请备注：<code>XQuant 读者</code>。</p>',205)]))}const C=o(i,[["render",c]]);export{m as __pageData,C as default};
